def dois_maiores(lista):
    if len(lista) < 2:
        raise ValueError("A lista deve conter pelo menos dois elementos")

    maiores = set()
    for num in lista:
        if num > max(maires):
            maiores.clear()
            maiores.add(num)
        elif num == max(maires):
            maiores.add(num)

    return tuple(sorted(maiores)[:2])

